function uuidv4() {
  if (globalThis.crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}
const root = $input.first().json || {};
let body = root.body || root;
// Replay payloads may carry the full webhook envelope ({headers,query,body}); unwrap it.
if (body && typeof body === 'object' && body.body && typeof body.body === 'object' && (body.headers || body.query || body.webhookUrl)) body = body.body;
const replay = !!root.replay;
const response_required = !!root.body && !replay;
const window_days = Number(body.window_days || $env.RENEWAL_WINDOW_DAYS || 45);
const dateBucket = new Date().toISOString().slice(0, 10);
const tenant_id = body.tenant_id || root.tenant_id || null;
const event_id = body.event_id || body.run_id || ('renewal-' + (response_required ? 'manual-' : '') + (tenant_id || 'batch') + '-' + dateBucket);
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();
return [{ json: {
  tenant_id,
  event_id,
  idem_key: 'renewal:' + event_id,
  window_days,
  force: !!body.force || !!tenant_id,
  replay,
  response_required,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, '')
} }];

const p = $('Normalize Run').first().json;
const H = { apikey: $env.SUPABASE_SERVICE_KEY, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY, accept: 'application/json' };
const J = { ...H, 'Content-Type': 'application/json', Prefer: 'return=representation' };
const helpers = this.helpers;
async function get(path) {
  return await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: H, json: true });
}
async function post(path, body) {
  return await helpers.httpRequest({ method: 'POST', url: p.supabase_url + path, headers: J, body, json: true });
}
function addDays(d, days) {
  const x = new Date(d);
  x.setUTCDate(x.getUTCDate() + days);
  return x;
}
function nextAnnual(createdAt) {
  const created = new Date(createdAt);
  const now = new Date();
  let due = new Date(Date.UTC(now.getUTCFullYear(), created.getUTCMonth(), created.getUTCDate()));
  if (due < now) due = new Date(Date.UTC(now.getUTCFullYear() + 1, created.getUTCMonth(), created.getUTCDate()));
  return due;
}
function riskLevel(tenant, risks) {
  const score = Number(tenant.health_score || 100);
  if (score < 40 || risks.some(r => r.status === 'error')) return 'critical';
  if (score < 60 || risks.length >= 2) return 'high';
  if (score < 80 || risks.length === 1) return 'watch';
  return 'low';
}
const tenantFilter = p.tenant_id ? ('id=eq.' + p.tenant_id + '&') : '';
const tenants = await get('/rest/v1/tenants?' + tenantFilter + 'status=eq.active&select=id,name,plan,region,status,health_score,created_at');
const now = new Date();
const windowEnd = addDays(now, p.window_days);
const selected = (tenants || []).filter(t => {
  const due = nextAnnual(t.created_at);
  return p.force || due <= windowEnd;
});
const packages = [];
for (const tenant of selected) {
  const due = nextAnnual(tenant.created_at);
  // One live package per (tenant, due date): daily cron / manual re-runs with fresh
  // event_ids would otherwise stack identical draft/scheduled rows.
  const existing = await get('/rest/v1/renewal_packages?tenant_id=eq.' + tenant.id + '&renewal_due_at=eq.' + encodeURIComponent(due.toISOString()) + '&status=in.(draft,scheduled)&select=id&limit=1');
  if (Array.isArray(existing) && existing.length > 0) {
    packages.push({ tenant_id: tenant.id, tenant_name: tenant.name, renewal_due_at: due.toISOString(), risk_level: null, status: 'already-exists', package_id: existing[0].id });
    continue;
  }
  // The three per-tenant reads are independent -> fetch concurrently.
  const [audit, invoices, ents] = await Promise.all([
    get('/rest/v1/audit_log?tenant_id=eq.' + tenant.id + '&select=service,step,status,payload,created_at&order=created_at.desc&limit=25'),
    get('/rest/v1/invoices?tenant_id=eq.' + tenant.id + '&select=stripe_id,status,amount,attempt,created_at&order=created_at.desc&limit=10'),
    get('/rest/v1/entitlements?tenant_id=eq.' + tenant.id + '&select=feature,enabled')
  ]);
  // Only recent problems poison the risk level; a transient error weeks ago must not
  // flip renewal strategy forever.
  const riskCutoff = Date.now() - 14 * 86400000;
  const risks = (audit || []).filter(a => (a.status === 'waiting' || a.status === 'error') && Date.parse(a.created_at) >= riskCutoff);
  const level = riskLevel(tenant, risks);
  const md = [
    '# Renewal package: ' + tenant.name,
    '',
    '- Tenant: ' + tenant.id,
    '- Plan: ' + tenant.plan,
    '- Region: ' + tenant.region,
    '- Health score: ' + tenant.health_score,
    '- Renewal due: ' + due.toISOString(),
    '- Risk level: ' + level,
    '- Open risks: ' + risks.length,
    '- Recent invoices: ' + (invoices || []).length,
    '- Enabled entitlements: ' + (ents || []).filter(e => e.enabled).map(e => e.feature).join(', '),
    '',
    'Recommended outreach: ' + (level === 'critical' || level === 'high' ? 'CSM save-plan before renewal ask.' : 'Expansion conversation with health proof points.')
  ].join('\n');
  const pkg = { tenant, renewal_due_at: due.toISOString(), risks, invoices, entitlements: ents, recommendation: level === 'critical' || level === 'high' ? 'save-plan' : 'expansion-outreach' };
  const row = await post('/rest/v1/renewal_packages', {
    tenant_id: tenant.id,
    correlation_id: p.correlation_id,
    renewal_due_at: due.toISOString(),
    risk_level: level,
    status: level === 'critical' ? 'draft' : 'scheduled',
    package_md: md,
    package: pkg
  });
  packages.push({ tenant_id: tenant.id, tenant_name: tenant.name, renewal_due_at: due.toISOString(), risk_level: level, status: Array.isArray(row) && row[0] ? row[0].status : null, package_id: Array.isArray(row) && row[0] ? row[0].id : null });
}
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, package_count: packages.length, packages, generated_at: new Date().toISOString() } }];

const b = $('Build Renewal Packages').first().json;
const text = ['FlowOps renewal run', 'Packages: ' + b.package_count, 'Correlation: `' + b.correlation_id + '`', ''].concat((b.packages || []).map(p => p.tenant_name + ': ' + p.risk_level + ' -> ' + p.status)).join('\n');
let alert_delivered = false;
let notice = null;
const token = $env.TELEGRAM_BOT_TOKEN;
const chat = $env.TELEGRAM_CHAT_ID;
if (token && chat && b.package_count > 0) {
  try {
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.telegram.org/bot' + token + '/sendMessage', body: { chat_id: chat, text, parse_mode: 'Markdown' }, json: true });
    alert_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else if (b.package_count === 0) {
  notice = 'telegram skipped: no renewal packages';
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}
return [{ json: { ...b, alert_delivered, notice } }];
